                        let state = app_handle.state::<meet_call::MeetCallState>();
                        let request_id = format!(
                            "dev-auto-{}",
                            std::time::SystemTime::now()
                                .duration_since(std::time::UNIX_EPOCH)
                                .map(|d| d.as_secs())
                                .unwrap_or(0)
                        );
                        let args = meet_call::OpenWindowArgs {
                            request_id: request_id.clone(),
                            meet_url: meet_url.clone(),
                            display_name: "OpenHuman Dev".to_string(),
                            // Dev-auto launch has no real user identity — the
                            // wake gate will fail-closed (no wakes fire) which
                            // is the safe posture for an automated harness.
                            owner_display_name: String::new(),
                        };
                        match meet_call::meet_call_open_window(app_handle.clone(), state, args)
                            .await
                        {
                            Ok(label) => log::info!(
                                "[dev-auto-meet] spawned label={label} request_id={request_id} url={meet_url}"
                            ),
                            Err(e) => log::error!(
                                "[dev-auto-meet] failed: {e} (url={meet_url})"
                            ),
                        }
                    });
                }
            }

            #[cfg(target_os = "macos")]
            {
                use std::sync::Arc;
                // The scanner task self-gates on `channels_config.imessage` via
                // JSON-RPC each tick — it stays idle until the user connects
                // iMessage and stops ingesting as soon as they disconnect. We
                // spawn it here just so the loop is live and picks up state
                // changes without requiring an app restart.
                if let Some(registry) = app.try_state::<Arc<imessage_scanner::ScannerRegistry>>() {
                    let registry = registry.inner().clone();
                    let app_handle = app.handle().clone();
                    registry.ensure_scanner(app_handle, "default".to_string());
                    log::info!("[imessage] scanner scheduled (gates on config each tick)");
                }
            }
            Ok(())
        })
